const busy = props.loading || props.state === 'loading'
const inactive = props.disabled || props.state === 'disabled' || busy
</script>
<template><main data-component="button" :data-state="state" data-part="root" class="p-8"><button data-kumo-component="Button" :class="[base, state === 'default' && 'cursor-pointer', state === 'disabled' && 'cursor-not-allowed opacity-50']" type="button" data-part="control" :disabled="inactive" @click="emit('operation', { operation: 'click' })"><svg v-if="busy" xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" stroke="currentColor" role="status" aria-label="Loading" style="height:14px;width:14px"><circle cx="12" cy="12" r="9.5" fill="none" stroke-width="2" stroke-linecap="round"><animateTransform attributeName="transform" type="rotate" from="0 12 12" to="360 12 12" dur="2s" repeatCount="indefinite"/><animate attributeName="stroke-dasharray" values="0 150;42 150;42 150" keyTimes="0;0.5;1" dur="1.5s" repeatCount="indefinite"/><animate attributeName="stroke-dashoffset" values="0;-16;-59" keyTimes="0;0.5;1" dur="1.5s" repeatCount="indefinite"/></circle><circle cx="12" cy="12" r="9.5" fill="none" stroke-width="2" stroke-linecap="round" opacity="0.1"/></svg><span class="contents">{{ busy ? 'Loading' : 'Continue' }}</span></button></main></template>
